function App() {
  const [workspace, setWorkspace] = useState('C:/my-project');
  const [model, setModel] = useState('balanced');
  const [status, setStatus] = useState('Idle');
  const [progress, setProgress] = useState('');
  const [chat, setChat] = useState([]);
  const [input, setInput] = useState('');
  const [isIndexing, setIsIndexing] = useState(false);
  const [isThinking, setIsThinking] = useState(false);

  function cosineSim(a, b) {
    var dot = 0, magA = 0, magB = 0;
    for (var i = 0; i < a.length; i++) {
      dot += a[i] * b[i];
      magA += a[i] * a[i];
      magB += b[i] * b[i];
    }
    return dot / (Math.sqrt(magA) * Math.sqrt(magB) + 1e-10);
  }

  var buildIndex = function() {
    if (!workspace || isIndexing) return;
    setIsIndexing(true);
    setStatus('Setting up database...');
    stuard.callNode('setup_db', {}).then(function() {
      setStatus('Scanning files...');
      return stuard.callNode('scan_files', { workspace: workspace });
    }).then(function(scanRes) {
      if (!scanRes.ok) {
        setStatus('Error scanning files');
        setIsIndexing(false);
        return Promise.reject('scan_failed');
      }
      var files = [];
      try {
        files = JSON.parse(scanRes.stdout);
      } catch(e) {
        setStatus('Error parsing files');
        setIsIndexing(false);
        return Promise.reject('parse_failed');
      }
      setStatus('Found ' + files.length + ' files. Indexing...');

      var processFile = function(idx) {
        if (idx >= files.length) {
          setStatus('Ready (' + files.length + ' files indexed)');
          setProgress('');
          setIsIndexing(false);
          return Promise.resolve();
        }
        var file = files[idx];
        setProgress('(' + (idx+1) + '/' + files.length + ') ' + file);
        return stuard.callNode('read_chunk', { path: file }).then(function(readRes) {
          if (!readRes.ok || !readRes.content) return processFile(idx + 1);
          var text = readRes.content;
          var chunkSize = 4000;
          var chunks = [];
          for (var j = 0; j < text.length; j += chunkSize) {
            chunks.push(text.substring(j, j + chunkSize));
          }
          var processChunk = function(c) {
            if (c >= chunks.length) return processFile(idx + 1);
            var chunkText = chunks[c];
            return stuard.callNode('embed_chunk', { text: chunkText }).then(function(embedRes) {
              if (embedRes.ok && embedRes.embeddings && embedRes.embeddings.length > 0) {
                var vector = embedRes.embeddings[0];
                return stuard.callNode('store_embedding', {
                  id: file + '#' + c,
                  path: file,
                  content: chunkText,
                  vector_json: JSON.stringify(vector)
                }).then(function() { return processChunk(c + 1); });
              }
              return processChunk(c + 1);
            });
          };
          return processChunk(0);
        });
      };
      return processFile(0);
    }).catch(function(err) {
      if (err !== 'scan_failed' && err !== 'parse_failed') {
        setStatus('Error: ' + (err.message || err));
        setIsIndexing(false);
      }
    });
  };

  var sendMessage = function() {
    if (!input.trim() || isThinking) return;
    var userMsg = input;
    setInput('');
    setChat(function(prev) { return prev.concat([{ role: 'user', text: userMsg }]); });
    setIsThinking(true);

    stuard.callNode('semantic_search', { query: userMsg }).then(function(embedRes) {
      if (!embedRes.ok || !embedRes.embeddings) throw new Error('Failed to embed query');
      var queryVector = embedRes.embeddings[0];
      return stuard.callNode('fetch_all_embeddings', {}).then(function(dbRes) {
        if (!dbRes.ok || !dbRes.results) throw new Error('Failed to fetch DB');
        var candidates = dbRes.results.map(function(row) {
          return { vector: JSON.parse(row.vector_json), path: row.path, content: row.content };
        });
        candidates.forEach(function(c) {
          c.score = cosineSim(queryVector, c.vector);
        });
        candidates.sort(function(a, b) { return b.score - a.score; });
        var topK = candidates.slice(0, 5);
        var contextText = 'No relevant code found.';
        if (topK.length > 0) {
          contextText = topK.map(function(r) {
            return 'File: ' + r.path + '\n' + r.content;
          }).join('\n\n---\n\n');
        }
        var prompt = 'Context from codebase:\n' + contextText + '\n\nUser Question: ' + userMsg;
        return stuard.callNode('agent_think', { prompt: prompt, model: model });
      });
    }).then(function(agentRes) {
      if (agentRes && agentRes.ok) {
        setChat(function(prev) { return prev.concat([{ role: 'agent', text: agentRes.text || 'No response' }]); });
      } else {
        setChat(function(prev) { return prev.concat([{ role: 'agent', text: 'Error: ' + (agentRes ? agentRes.error : 'unknown') }]); });
      }
      setIsThinking(false);
    }).catch(function(err) {
      setChat(function(prev) { return prev.concat([{ role: 'agent', text: 'Error: ' + (err.message || err) }]); });
      setIsThinking(false);
    });
  };

  return (
    <div style={{display:'flex', height:'100%', background:'#0f172a', color:'#e2e8f0', fontFamily:'system-ui, sans-serif'}}>
      <div style={{width:'240px', background:'#020617', padding:'16px', display:'flex', flexDirection:'column', borderRight:'1px solid #1e293b'}}>
        <h1 style={{fontSize:'18px', fontWeight:'bold', color:'#60a5fa', marginBottom:'24px'}}>Local RAG Coder</h1>

        <label style={{fontSize:'11px', color:'#94a3b8', marginBottom:'4px', textTransform:'uppercase', letterSpacing:'0.05em'}}>Workspace Path</label>
        <input
          value={workspace}
          onChange={function(e) { setWorkspace(e.target.value); }}
          style={{width:'100%', background:'#1e293b', border:'1px solid #334155', borderRadius:'6px', padding:'8px', fontSize:'13px', color:'#e2e8f0', marginBottom:'16px', outline:'none', boxSizing:'border-box'}}
          placeholder="C:/my-project"
        />

        <label style={{fontSize:'11px', color:'#94a3b8', marginBottom:'4px', textTransform:'uppercase', letterSpacing:'0.05em'}}>AI Model</label>
        <select
          value={model}
          onChange={function(e) { setModel(e.target.value); }}
          style={{width:'100%', background:'#1e293b', border:'1px solid #334155', borderRadius:'6px', padding:'8px', fontSize:'13px', color:'#e2e8f0', marginBottom:'24px', outline:'none', boxSizing:'border-box'}}
        >
          <option value="fast">Fast</option>
          <option value="balanced">Balanced</option>
          <option value="smart">Smart</option>
        </select>

        <button
          onClick={buildIndex}
          disabled={isIndexing}
          style={{width:'100%', padding:'10px', borderRadius:'6px', fontWeight:'600', fontSize:'13px', border:'none', cursor: isIndexing ? 'not-allowed' : 'pointer', background: isIndexing ? '#334155' : '#2563eb', color: isIndexing ? '#94a3b8' : 'white', transition:'background 0.15s'}}
        >
          {isIndexing ? 'Indexing...' : 'Build Index'}
        </button>

        <div style={{marginTop:'16px', fontSize:'13px', color:'#94a3b8'}}>
          <div style={{fontWeight:'500', color:'#cbd5e1'}}>Status: {status}</div>
          {progress ? <div style={{fontSize:'11px', marginTop:'4px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap'}} title={progress}>{progress}</div> : null}
        </div>
      </div>

      <div style={{flex:1, display:'flex', flexDirection:'column', minWidth:0}}>
        <div style={{flex:1, overflowY:'auto', padding:'24px', display:'flex', flexDirection:'column', gap:'12px'}}>
          {chat.length === 0 ? (
            <div style={{flex:1, display:'flex', alignItems:'center', justifyContent:'center', color:'#64748b'}}>
              Index your codebase, then ask a question!
            </div>
          ) : (
            chat.map(function(msg, i) {
              return (
                <div key={i} style={{display:'flex', justifyContent: msg.role === 'user' ? 'flex-end' : 'flex-start'}}>
                  <div style={{maxWidth:'80%', borderRadius:'12px', padding:'12px 16px', background: msg.role === 'user' ? '#2563eb' : '#1e293b', color: msg.role === 'user' ? 'white' : '#e2e8f0', border: msg.role === 'user' ? 'none' : '1px solid #334155'}}>
                    <div style={{fontSize:'10px', opacity:0.5, marginBottom:'4px', textTransform:'uppercase', letterSpacing:'0.05em'}}>{msg.role}</div>
                    <div style={{whiteSpace:'pre-wrap', fontSize:'13px', lineHeight:'1.5'}}>{msg.text}</div>
                  </div>
                </div>
              );
            })
          )}
          {isThinking ? (
            <div style={{display:'flex', justifyContent:'flex-start'}}>
              <div style={{background:'#1e293b', border:'1px solid #334155', borderRadius:'12px', padding:'12px 16px', fontSize:'13px', color:'#94a3b8'}}>
                Agent is thinking...
              </div>
            </div>
          ) : null}
        </div>

        <div style={{padding:'16px', background:'#020617', borderTop:'1px solid #1e293b'}}>
          <div style={{display:'flex', gap:'8px'}}>
            <input
              value={input}
              onChange={function(e) { setInput(e.target.value); }}
              onKeyDown={function(e) { if (e.key === 'Enter') sendMessage(); }}
              placeholder="Ask about your code..."
              style={{flex:1, background:'#1e293b', border:'1px solid #334155', borderRadius:'8px', padding:'12px', fontSize:'13px', color:'#e2e8f0', outline:'none', boxSizing:'border-box'}}
              disabled={isThinking}
            />
            <button
              onClick={sendMessage}
              disabled={isThinking || !input.trim()}
              style={{padding:'10px 24px', borderRadius:'8px', fontWeight:'600', fontSize:'13px', border:'none', cursor: (isThinking || !input.trim()) ? 'not-allowed' : 'pointer', background: (isThinking || !input.trim()) ? '#334155' : '#2563eb', color: (isThinking || !input.trim()) ? '#64748b' : 'white', transition:'background 0.15s'}}
            >
              Send
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

