import os, json
ignore_dirs = {'.git', 'node_modules', 'venv', '__pycache__', 'dist', 'build', '.next'}
valid_exts = {'.js', '.ts', '.py', '.html', '.css', '.json', '.md', '.jsx', '.tsx', '.java', '.c', '.cpp', '.h', '.go', '.rs'}
files = []
workspace = r'{{caller.workspace}}'
for root, dirs, filenames in os.walk(workspace):
    dirs[:] = [d for d in dirs if d not in ignore_dirs]
    for f in filenames:
        if any(f.endswith(ext) for ext in valid_exts):
            files.append(os.path.join(root, f).replace('\\', '/'))
print(json.dumps(files))
